import secureStorage from '../utils/secureStorage';
import encryptionService from '../utils/encryptionService';

const PAYMENT_METHODS_KEY = 'payment_methods';

class PaymentInfoStore {
  /**
   * Mask card number for display (show last 4 digits)
   */
  _maskCardNumber(cardNumber) {
    const cleaned = cardNumber.replace(/\s/g, '');
    if (cleaned.length < 4) return '****';
    return `****${cleaned.slice(-4)}`;
  }

  /**
   * Detect card type from number
   */
  _detectCardType(cardNumber) {
    const cleaned = cardNumber.replace(/\s/g, '');

    if (/^4/.test(cleaned)) return 'visa';
    if (/^5[1-5]/.test(cleaned)) return 'mastercard';
    if (/^3[47]/.test(cleaned)) return 'amex';
    if (/^6(?:011|5)/.test(cleaned)) return 'discover';
    return 'unknown';
  }

  /**
   * Save a payment method securely
   * @param {Object} paymentMethod - { cardNumber, expiryMonth, expiryYear, cvv, cardholderName, billingAddress }
   */
  async addPaymentMethod(paymentMethod) {
    const existingMethods = (await this.getPaymentMethods()) || [];

    const id = `pm_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
    const cardFingerprint = encryptionService.hash(
      paymentMethod.cardNumber.replace(/\s/g, '')
    );

    // Check for duplicate cards
    const duplicate = existingMethods.find(
      (m) => m.cardFingerprint === cardFingerprint
    );
    if (duplicate) {
      throw new Error('This card has already been added');
    }

    const securePaymentMethod = {
      id,
      cardNumber: paymentMethod.cardNumber.replace(/\s/g, ''),
      expiryMonth: paymentMethod.expiryMonth,
      expiryYear: paymentMethod.expiryYear,
      cvv: paymentMethod.cvv,
      cardholderName: paymentMethod.cardholderName || '',
      billingAddress: paymentMethod.billingAddress || {},
      maskedNumber: this._maskCardNumber(paymentMethod.cardNumber),
      cardType: this._detectCardType(paymentMethod.cardNumber),
      cardFingerprint,
      isDefault: existingMethods.length === 0,
      createdAt: Date.now(),
      updatedAt: Date.now(),
    };

    existingMethods.push(securePaymentMethod);
    await secureStorage.setItem(PAYMENT_METHODS_KEY, existingMethods);

    // Return a safe version without sensitive data
    return this._sanitizeForDisplay(securePaymentMethod);
  }

  /**
   * Get all payment methods (with sensitive data)
   */
  async getPaymentMethods() {
    return (await secureStorage.getItem(PAYMENT_METHODS_KEY)) || [];
  }

  /**
   * Get all payment methods safe for display
   */
  async getPaymentMethodsForDisplay() {
    const methods = await this.getPaymentMethods();
    return methods.map((m) => this._sanitizeForDisplay(m));
  }

  /**
   * Get a specific payment method by ID
   */
  async getPaymentMethodById(id) {
    const methods = await this.getPaymentMethods();
    return methods.find((m) => m.id === id) || null;
  }

  /**
   * Get full card details for a specific payment (e.g., during checkout)
   */
  async getFullCardDetails(id) {
    const method = await this.getPaymentMethodById(id);
    if (!method) {
      throw new Error('Payment method not found');
    }
    return method;
  }

  /**
   * Remove a payment method
   */
  async removePaymentMethod(id) {
    const methods = await this.getPaymentMethods();
    const filteredMethods = methods.filter((m) => m.id !== id);

    if (filteredMethods.length === methods.length) {
      throw new Error('Payment method not found');
    }

    // If removed method was default, set first remaining as default
    if (filteredMethods.length > 0) {
      const hasDefault = filteredMethods.some((m) => m.isDefault);
      if (!hasDefault) {
        filteredMethods[0].isDefault = true;
      }
    }

    await secureStorage.setItem(PAYMENT_METHODS_KEY, filteredMethods);
    return true;
  }

  /**
   * Set a payment method as default
   */
  async setDefaultPaymentMethod(id) {
    const methods = await this.getPaymentMethods();
    const updatedMethods = methods.map((m) => ({
      ...m,
      isDefault: m.id === id,
      updatedAt: m.id === id ? Date.now() : m.updatedAt,
    }));

    await secureStorage.setItem(PAYMENT_METHODS_KEY, updatedMethods);
    return true;
  }

  /**
   * Clear all payment methods
   */
  async clearAll() {
    await secureStorage.removeItem(PAYMENT_METHODS_KEY);
    return true;
  }

  /**
   * Sanitize payment method for display (remove sensitive fields)
   */
  _sanitizeForDisplay(method) {
    return {
      id: method.id,
      maskedNumber: method.maskedNumber,
      cardType: method.cardType,
      expiryMonth: method.expiryMonth,
      expiryYear: method.expiryYear,
      cardholderName: method.cardholderName,
      isDefault: method.isDefault,
      createdAt: method.createdAt,
    };
  }
}

