import secureStorage from '../utils/secureStorage';
import encryptionService from '../utils/encryptionService';

const AUTH_TOKENS_KEY = 'auth_tokens';
const TOKEN_METADATA_KEY = 'auth_token_metadata';

class AuthTokenStore {
  /**
   * Save authentication tokens
   * @param {Object} tokens - { accessToken, refreshToken, idToken?, tokenType?, scope? }
   * @param {number} expiresIn - Token expiry in seconds
   */
  async saveTokens(tokens, expiresIn = 3600) {
    const tokenData = {
      accessToken: tokens.accessToken,
      refreshToken: tokens.refreshToken || '',
      idToken: tokens.idToken || '',
      tokenType: tokens.tokenType || 'Bearer',
      scope: tokens.scope || '',
      expiresAt: Date.now() + expiresIn * 1000,
      issuedAt: Date.now(),
    };

    const metadata = {
      tokenHash: encryptionService.hash(tokens.accessToken),
      expiresAt: tokenData.expiresAt,
      issuedAt: tokenData.issuedAt,
      tokenType: tokenData.tokenType,
    };

    await secureStorage.multiSet([
      [AUTH_TOKENS_KEY, tokenData],
      [TOKEN_METADATA_KEY, metadata],
    ]);

    return metadata;
  }

  /**
   * Get the access token
   */
  async getAccessToken() {
    const tokenData = await secureStorage.getItem(AUTH_TOKENS_KEY);

    if (!tokenData) {
      return null;
    }

    if (this._isTokenExpired(tokenData.expiresAt)) {
      return null;
    }

    return tokenData.accessToken;
  }

  /**
   * Get the refresh token
   */
  async getRefreshToken() {
    const tokenData = await secureStorage.getItem(AUTH_TOKENS_KEY);

    if (!tokenData) {
      return null;
    }

    return tokenData.refreshToken || null;
  }

  /**
   * Get all tokens
   */
  async getTokens() {
    const tokenData = await secureStorage.getItem(AUTH_TOKENS_KEY);

    if (!tokenData) {
      return null;
    }

    return {
      ...tokenData,
      isExpired: this._isTokenExpired(tokenData.expiresAt),
      expiresInMs: Math.max(0, tokenData.expiresAt - Date.now()),
    };
  }

  /**
   * Get the authorization header value
   */
  async getAuthorizationHeader() {
    const tokenData = await secureStorage.getItem(AUTH_TOKENS_KEY);

    if (!tokenData || this._isTokenExpired(tokenData.expiresAt)) {
      return null;
    }

    return `${tokenData.tokenType} ${tokenData.accessToken}`;
  }

  /**
   * Check if tokens exist and are valid
   */
  async isAuthenticated() {
    try {
      const tokenData = await secureStorage.getItem(AUTH_TOKENS_KEY);

      if (!tokenData) {
        return false;
      }

      return !this._isTokenExpired(tokenData.expiresAt);
    } catch {
      return false;
    }
  }

  /**
   * Check if the access token needs refresh (within buffer window)
   * @param {number} bufferSeconds - seconds before expiry to trigger refresh
   */
  async needsRefresh(bufferSeconds = 300) {
    const tokenData = await secureStorage.getItem(AUTH_TOKENS_KEY);

    if (!tokenData) {
      return true;
    }

    const bufferMs = bufferSeconds * 1000;
    return Date.now() >= tokenData.expiresAt - bufferMs;
  }

  /**
   * Update tokens after a refresh
   */
  async updateTokens(newTokens, expiresIn = 3600) {
    const currentTokens = await secureStorage.getItem(AUTH_TOKENS_KEY);

    const updatedTokenData = {
      accessToken: newTokens.accessToken,
      refreshToken: newTokens.refreshToken || currentTokens?.refreshToken || '',
      idToken: newTokens.idToken || currentTokens?.idToken || '',
      tokenType: newTokens.tokenType || currentTokens?.tokenType || 'Bearer',
      scope: newTokens.scope || currentTokens?.scope || '',
      expiresAt: Date.now() + expiresIn * 1000,
      issuedAt: Date.now(),
      previousTokenHash: currentTokens
        ? encryptionService.hash(currentTokens.accessToken)
        : null,
    };

    const metadata = {
      tokenHash: encryptionService.hash(newTokens.accessToken),
      expiresAt: updatedTokenData.expiresAt,
      issuedAt: updatedTokenData.issuedAt,
      tokenType: updatedTokenData.tokenType,
      refreshCount: (currentTokens?.refreshCount || 0) + 1,
    };

    await secureStorage.multiSet([
      [AUTH_TOKENS_KEY, updatedTokenData],
      [TOKEN_METADATA_KEY, metadata],
    ]);

    return metadata;
  }

  /**
   * Clear all auth tokens (logout)
   */
  async clearTokens() {
    await Promise.all([
      secureStorage.removeItem(AUTH_TOKENS_KEY),
      secureStorage.removeItem(TOKEN_METADATA_KEY),
    ]);
    return true;
  }

  /**
   * Get token metadata (non-sensitive info)
   */
  async getTokenMetadata() {
    return await secureStorage.getItem(TOKEN_METADATA_KEY);
  }

  /**
   * Check if token is expired
   */
  _isTokenExpired(expiresAt) {
    return Date.now() >= expiresAt;
  }
}

