// hooks/useSecureStorage.js
import { useState, useEffect, useCallback } from 'react';
import secureStorage from '../utils/secureStorage';

export function useSecureStorage(key, defaultValue = null) {
  const [value, setValue] = useState(defaultValue);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const loadValue = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const storedValue = await secureStorage.getItem(key);
      setValue(storedValue !== null ? storedValue : defaultValue);
    } catch (err) {
      setError(err);
      setValue(defaultValue);
    } finally {
      setLoading(false);
    }
  }, [key, defaultValue]);

  useEffect(() => {
    loadValue();
  }, [loadValue]);

  const setSecureValue = useCallback(
    async (newValue) => {
      try {
        setError(null);
        if (newValue === null || newValue === undefined) {
          await secureStorage.removeItem(key);
          setValue(defaultValue);
        } else {
          await secureStorage.setItem(key, newValue);
          setValue(newValue);
        }
      } catch (err) {
        setError(err);
        throw err;
      }
    },
    [key, defaultValue]
  );

  const removeValue = useCallback(async () => {
    try {
      setError(null);
      await secureStorage.removeItem(key);
      setValue(defaultValue);
    } catch (err) {
      setError(err);
      throw err;
    }
  }, [key, defaultValue]);

  return {
    value,
    setValue: setSecureValue,
    removeValue,
    loading,
    error,
    refresh: loadValue,
  };
}

// hooks/useAuth.js
import { useState, useEffect, useCallback } from 'react';
import authTokenStore from '../models/AuthTokenStore';

export function useAuth() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);
  const [tokenMetadata, setTokenMetadata] = useState(null);

  const checkAuth = useCallback(async () => {
    try {
      setLoading(true);
      const authenticated = await authTokenStore.isAuthenticated();
      setIsAuthenticated(authenticated);

      if (authenticated) {
        const metadata = await authTokenStore.getTokenMetadata();
        setTokenMetadata(metadata);
      } else {
        setTokenMetadata(null);
      }
    } catch (error) {
      console.error('Auth check error:', error);
      setIsAuthenticated(false);
      setTokenMetadata(null);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    checkAuth();
  }, [checkAuth]);

  const login = useCallback(async (tokens, expiresIn) => {
    const metadata = await authTokenStore.saveTokens(tokens, expiresIn);
    setIsAuthenticated(true);
    setTokenMetadata(metadata);
    return metadata;
  }, []);

  const logout = useCallback(async () => {
    await authTokenStore.clearTokens();
    setIsAuthenticated(false);
    setTokenMetadata(null);
  }, []);

  const getAuthHeader = useCallback(async () => {
    return await authTokenStore.getAuthorizationHeader();
  }, []);

  const refreshTokens = useCallback(async (newTokens, expiresIn) => {
    const metadata = await authTokenStore.updateTokens(newTokens, expiresIn);
    setTokenMetadata(metadata);
    return metadata;
  }, []);

  return {
    isAuthenticated,
    loading,
    tokenMetadata,
    login,
    logout,
    getAuthHeader,
    refreshTokens,
    checkAuth,
  };
}

